      <div id="apiKeyModalLabelWrap">
        <label for="apiKeyModalLabel">Name</label>
        <input id="apiKeyModalLabel" type="text" maxlength="128" placeholder="e.g. CAFM Production" autocomplete="off" />
      </div>
